import json
from pathlib import Path

zoo = Path('/local/nick/AutoIREE_zoo/models')
meta_keys = {'model','iterations','algorithm','total_default_cycle','total_best_search_cycle','total_tuning_time','fmt tuning time'}

for model_dir in sorted(zoo.iterdir()):
    if not model_dir.is_dir():
        continue
    records = []
    for rj in model_dir.rglob('record.json'):
        try:
            d = json.loads(rj.read_text())
        except: continue
        if d.get('algorithm') == 'ai_rank':
            records.append((rj, d))
    if not records:
        continue
    rj, d = sorted(records, key=lambda x: x[0].parent.name)[-1]

    dispatches = {k:v for k,v in d.items() if k not in meta_keys and isinstance(v, dict)}
    total_default = sum(v.get('default_cycle',0) for v in dispatches.values())
    total_best = sum(v.get('best_search_cycle',0) for v in dispatches.values())
    ai_wins = sum(1 for v in dispatches.values() if v.get('best_search_cycle',0) < v.get('default_cycle',0))
    n = len(dispatches)
    speedup = total_default / total_best if total_best > 0 else 0

    print(f'{model_dir.name}: {n} dispatches, baseline={total_default:,} AI-tune={total_best:,} speedup={speedup:.2f}x  (AI wins {ai_wins}/{n})')
"

