"""Adapter layer: convert AutoIREE MLIRTask/ConfigEntity to ModelzooRanker features."""
from __future__ import annotations

import json
import math
from typing import TYPE_CHECKING

import numpy as np

from auto_iree.ai_rank.features import (
    compute_feature_a, compute_feature_b, _parse_int_list,
)

if TYPE_CHECKING:
    from auto_iree.task import MLIRTask
    from auto_iree.space import ConfigEntity


def load_tile_config(task: MLIRTask) -> dict:
    """Load and return tile_config.json as a dict for the given task."""
    with open(task.default_tile_file, "r") as f:
        return json.load(f)


def _get_body_op_name(tile_config: dict) -> str:
    """Find the main body op name (not linalg.fill) in tile_config."""
    for key in tile_config:
        if key.startswith('linalg.') and key != 'linalg.fill-0' and key != 'linalg.yield':
            return key
    return next(iter(tile_config))


def _compute_total_elements(tile_config: dict, op_name: str) -> int:
    """Compute product of iteration space dims for the body op."""
    body_op = tile_config.get(op_name)
    if body_op is None:
        return 1
    iteration_space = _parse_int_list(body_op['iteration_space'])
    total = 1
    for d in iteration_space:
        total *= d
    return total


def extract_feature_a(task: MLIRTask) -> np.ndarray:
    """Extract 18-dim Feature A from an MLIRTask.

    Reads tile_config.json from the task's benchmark dir and builds
    the group dict expected by compute_feature_a.
    """
    tile_config = load_tile_config(task)
    op_name = _get_body_op_name(tile_config)
    body_op = tile_config[op_name]
    iteration_space = _parse_int_list(body_op['iteration_space'])

    group = {
        'op_name': op_name,
        'shape': iteration_space,
        'configs': [{'lowering_config': [[0] * len(iteration_space)]}],
        'tile_config': tile_config,
    }
    return compute_feature_a(group)


def config_to_lowering(config: ConfigEntity, op_name: str) -> list[list[int]]:
    """Convert ConfigEntity.to_iree_format() to lowering_config for a specific op.

    Returns the lowering_config (list of lists) for op_name.
    Falls back to the first op if op_name not found.
    """
    iree_format = config.to_iree_format()
    if op_name in iree_format:
        return iree_format[op_name]
    return next(iter(iree_format.values()))


def extract_feature_b(config: ConfigEntity, op_name: str,
                      total_elements: int,
                      tile_config: dict) -> np.ndarray:
    """Extract 59-dim Feature B from a ConfigEntity.

    Args:
        config: AutoIREE ConfigEntity from the search space.
        op_name: The body op name (e.g., 'linalg.matmul-1').
        total_elements: Product of iteration space dims.
        tile_config: Parsed tile_config.json dict.
    """
    lowering_config = config_to_lowering(config, op_name)
    config_dict = {
        'lowering_config': lowering_config,
        'op_name': op_name,
    }
    return compute_feature_b(config_dict, total_elements=total_elements,
                              tile_config=tile_config)

"""Tests for ai_rank adapter layer."""
import json
import math
from pathlib import Path
from unittest.mock import MagicMock

import numpy as np
import pytest

from auto_iree.ai_rank.adapter import (
    extract_feature_a, extract_feature_b, config_to_lowering,
    load_tile_config, _get_body_op_name, _compute_total_elements,
)
from auto_iree.ai_rank.features import FEATURE_A_DIM, FEATURE_B_DIM


TILE_CONFIG_PATH = Path(__file__).parent.parent / "files" / "tile_config.json"


@pytest.fixture
def tile_config():
    with open(TILE_CONFIG_PATH) as f:
        return json.load(f)


@pytest.fixture
def mock_task(tile_config):
    task = MagicMock()
    task.default_tile_file = TILE_CONFIG_PATH
    task.subgraph_name = "module_main_dispatch_0"
    return task


class TestGetBodyOpName:
    def test_finds_matmul(self, tile_config):
        name = _get_body_op_name(tile_config)
        assert name == "linalg.matmul-1"

    def test_with_only_fill(self):
        tc = {"linalg.fill-0": {"iteration_space": "[10]"}}
        # Falls back to first key
        assert _get_body_op_name(tc) == "linalg.fill-0"


class TestComputeTotalElements:
    def test_matmul(self, tile_config):
        total = _compute_total_elements(tile_config, "linalg.matmul-1")
        assert total == 3136 * 128 * 64


class TestExtractFeatureA:
    def test_from_mock_task(self, mock_task):
        fa = extract_feature_a(mock_task)
        assert fa.shape == (FEATURE_A_DIM,)
        assert fa.dtype == np.float32
        # Should use linalg.matmul-1 as body op
        assert fa[0] == 0.0  # OP_TYPE_MAP['linalg.matmul-1'] = 0
        assert fa[1] == 3.0  # rank = 3
        assert fa[2] == 2.0  # 2 parallel dims
        assert fa[3] == 1.0  # 1 reduction dim
        assert fa[4] == 6.0  # 6 tiling levels


class TestConfigToLowering:
    def test_extracts_correct_op(self):
        config = MagicMock()
        config.to_iree_format.return_value = {
            'linalg.fill-0': [[0, 0], [0, 0], [0, 0], [0, 0]],
            'linalg.matmul-1': [[64, 32, 16], [8, 4, 0], [0, 0, 8], [0, 0, 0], [0, 0, 4], [0, 0, 0]],
        }
        lc = config_to_lowering(config, 'linalg.matmul-1')
        assert lc == [[64, 32, 16], [8, 4, 0], [0, 0, 8], [0, 0, 0], [0, 0, 4], [0, 0, 0]]

    def test_fallback_to_first_op(self):
        config = MagicMock()
        config.to_iree_format.return_value = {
            'linalg.matmul-1': [[64, 32, 16]],
        }
        lc = config_to_lowering(config, 'nonexistent-op')
        assert lc == [[64, 32, 16]]


class TestExtractFeatureB:
    def test_from_mock_config(self, tile_config):
        config = MagicMock()
        config.to_iree_format.return_value = {
            'linalg.matmul-1': [[64, 32, 16], [8, 4, 0], [0, 0, 8], [0, 0, 0], [0, 0, 4], [0, 0, 0]],
        }
        fb = extract_feature_b(
            config, 'linalg.matmul-1',
            total_elements=3136 * 128 * 64,
            tile_config=tile_config,
        )
        assert fb.shape == (FEATURE_B_DIM,)
        assert fb.dtype == np.float32
        # Check tile flat values
        assert fb[0] == 64.0  # level 0, dim 0
        assert fb[1] == 32.0  # level 0, dim 1
        assert fb[2] == 16.0  # level 0, dim 2

